func (rm *RouteManager) Add(route *Route) error {
	rm.Lock()
	defer rm.Unlock()
	factory, found := AdapterFactories.Lookup(route.AdapterType())
	if !found {
		return errors.New("bad adapter: " + route.Adapter)
	}
	adapter, err := factory(route)
	if err != nil {
		return err
	}
	if route.ID == "" {
		h := sha1.New() //nolint:gosec
		io.WriteString(h, strconv.Itoa(int(time.Now().UnixNano())))
		route.ID = fmt.Sprintf("%x", h.Sum(nil))[:12]
	}
	route.closer = make(chan struct{})
	route.adapter = adapter
	// Stop any existing route with this ID:
	if rm.routes[route.ID] != nil {
		rm.routes[route.ID].closer <- struct{}{}
	}

	rm.routes[route.ID] = route
	if rm.persistor != nil {
		if err := rm.persistor.Add(route); err != nil {
			log.Println("persistor:", err)
		}
	}
	if rm.routing {
		go rm.route(route)
	}
	return nil
}

func (t *tlsTransport) Dial(addr string, options map[string]string) (conn net.Conn, err error) {
	// at this point, if our trust store is empty, there is no point of continuing
	// since it would be impossible to successfully validate any x509 server certificates
	if len(clientTLSConfig.RootCAs.Subjects()) < 1 {
		err = fmt.Errorf("FATAL: TLS CA trust store is empty! Can not trust any TLS endpoints: tls://%s", addr)
		return
	}

	// attempt to establish the TLS connection
	conn, err = tls.Dial("tcp", addr, clientTLSConfig)
	return
}
